const { convertString } = require('./dist');

const testHtml = `
<table>
  <thead>
    <tr>
      <th>功能</th>
      <th>Claude Code</th>
      <th>oh-my-openagent</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>多模型支持</td>
      <td>仅 Claude</td>
      <td>支持所有主流模型</td>
    </tr>
    <tr>
      <td>价格</td>
      <td>$20/月</td>
      <td>按需付费</td>
    </tr>
    <tr>
      <td>自由度</td>
      <td>受限</td>
      <td>完全开源</td>
    </tr>
  </tbody>
</table>
`;

console.log('=== Testing Table Conversion ===\n');
console.log('Input HTML:');
console.log(testHtml);

const markdown = convertString(testHtml);

console.log('\n=== Output Markdown ===');
console.log(markdown);

if (markdown.includes('|') && markdown.includes('---')) {
  console.log('\n✅ Table conversion successful!');
} else {
  console.log('\n❌ Table conversion failed!');
}
